"use client"

import { useCallback, useEffect, useMemo, useRef, useState } from "react"
import { ChatInputProvider } from "./ChatInputContext"
import { CameraModal } from "./components/CameraModal"
import { useAttachments } from "./hooks/useAttachments"
import { useImageCapture } from "./hooks/useImageCapture"
import type { ChatInputConfig, ChatInputContextValue, ChatInputProps } from "./types"
import { AttachmentsGrid } from "./components/v3/AttachmentsGrid"
import { ErrorToast } from "./components/v3/ErrorToast"
import { InputGrid } from "./components/v3/InputGrid"
import { InputArea } from "./components/v3/InputArea"
import { Toolbar } from "./components/v3/Toolbar"
import { SendButton } from "./components/v3/SendButton"

/**
 * ChatInput V3 - Our clean style + better structure
 *
 * Architecture from ChatGPT:
 * - CSS Grid layout
 * - Data attributes for state
 * - Proper accessibility
 *
 * Visual style: Our own minimal design
 */
export function ChatInputV3({
  message,
  setMessage,
  busy,
  abortControllerRef,
  onSubmit,
  onStop,
  config: userConfig = {},
}: Omit<ChatInputProps, "children">) {
  const [isDragging, setIsDragging] = useState(false)
  const [error, setError] = useState<string | undefined>()
  const fileInputRef = useRef<HTMLInputElement>(null)

  const config: ChatInputConfig = useMemo(
    () => ({
      enableAttachments: true,
      enableCamera: false,
      maxAttachments: 10,
      maxFileSize: 10 * 1024 * 1024,
      placeholder: "Tell me what to change...",
      minHeight: "80px",
      maxHeight: "200px",
      onMessage: (msg, type) => {
        if (type === "error") {
          setError(msg)
          setTimeout(() => setError(undefined), 5000)
        }
      },
      ...userConfig,
    }),
    [userConfig],
  )

  const { attachments, addAttachment, removeAttachment } = useAttachments(config)

  const handlePhotoCapture = useCallback(
    (blob: Blob) => {
      const file = new File([blob], `photo-${Date.now()}.jpg`, { type: "image/jpeg" })
      addAttachment(file)
    },
    [addAttachment],
  )

  const { isCameraOpen, openCamera, closeCamera, capturePhoto } = useImageCapture(handlePhotoCapture)

  const canSubmit = useMemo(() => {
    if (busy) return false
    const hasMessage = message.trim().length > 0
    const hasAttachments = attachments.length > 0
    const attachmentsValid = attachments.every(a => !a.error && a.uploadProgress === 100)
    return (hasMessage || hasAttachments) && attachmentsValid
  }, [busy, message, attachments])

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
        e.preventDefault()
        document.querySelector<HTMLTextAreaElement>('[data-testid="message-input"]')?.focus()
      }
    }
    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [])

  const contextValue: ChatInputContextValue = useMemo(
    () => ({
      message,
      setMessage,
      attachments,
      addAttachment,
      removeAttachment,
      isCameraOpen,
      openCamera,
      closeCamera,
      capturePhoto,
      isDragging,
      setIsDragging,
      busy,
      abortControllerRef,
      canSubmit,
      error,
      onSubmit,
      onStop,
      config,
    }),
    [
      message,
      setMessage,
      attachments,
      addAttachment,
      removeAttachment,
      isCameraOpen,
      openCamera,
      closeCamera,
      capturePhoto,
      isDragging,
      busy,
      abortControllerRef,
      canSubmit,
      error,
      onSubmit,
      onStop,
      config,
    ],
  )

  // Drag & drop
  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    setIsDragging(true)
  }, [])

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
    if (e.currentTarget === e.target) setIsDragging(false)
  }, [])

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    e.stopPropagation()
  }, [])

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      e.stopPropagation()
      setIsDragging(false)
      const files = Array.from(e.dataTransfer.files)
      for (const file of files) addAttachment(file)
    },
    [addAttachment],
  )

  const handlePaste = useCallback(
    (e: React.ClipboardEvent) => {
      const items = Array.from(e.clipboardData.items)
      for (const item of items) {
        if (item.type.startsWith("image/")) {
          const file = item.getAsFile()
          if (file) addAttachment(file)
        }
      }
    },
    [addAttachment],
  )

  return (
    <ChatInputProvider value={contextValue}>
      {/* Hidden file input */}
      <input
        ref={fileInputRef}
        type="file"
        multiple
        accept={config.allowedFileTypes?.join(",") || "image/*,.pdf,.txt,.md"}
        onChange={e => {
          const files = Array.from(e.target.files || [])
          for (const file of files) addAttachment(file)
          if (fileInputRef.current) fileInputRef.current.value = ""
        }}
        className="sr-only"
        tabIndex={-1}
        aria-hidden="true"
      />

      <section
        className="flex-shrink-0 p-4 safe-area-inset-bottom"
        aria-label="Chat input"
        data-dragging={isDragging ? "" : undefined}
        onDragEnter={handleDragEnter}
        onDragLeave={handleDragLeave}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
        onPaste={handlePaste}
      >
        <InputGrid isDragging={isDragging}>
          {/* Error toast */}
          <ErrorToast />

          {/* Attachments */}
          <AttachmentsGrid />

          {/* Input area */}
          <InputArea />

          {/* Toolbar */}
          <Toolbar fileInputRef={fileInputRef} />

          {/* Send button */}
          <SendButton />
        </InputGrid>
      </section>

      <CameraModal />
    </ChatInputProvider>
  )
}
