"use client"

import { AlertCircle, X } from "lucide-react"
import { useEffect, useState } from "react"
import { useChatInput } from "../../ChatInputContext"

/**
 * Animated error toast with nice feedback
 */
export function ErrorToast() {
  const { error } = useChatInput()
  const [isVisible, setIsVisible] = useState(false)
  const [currentError, setCurrentError] = useState<string | undefined>()

  useEffect(() => {
    if (error) {
      setCurrentError(error)
      setIsVisible(true)
    } else {
      // Fade out animation
      const timeout = setTimeout(() => {
        setIsVisible(false)
        setTimeout(() => setCurrentError(undefined), 300) // Wait for fade out
      }, 100)
      return () => clearTimeout(timeout)
    }
  }, [error])

  if (!currentError) return null

  return (
    <div
      className={`absolute top-3 left-3 right-3 z-10 transition-all duration-300 ${
        isVisible ? "opacity-100 translate-y-0" : "opacity-0 -translate-y-2"
      }`}
    >
      <div className="flex items-start gap-3 px-4 py-3 rounded-lg bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800/50 shadow-lg">
        <AlertCircle className="size-5 text-red-600 dark:text-red-400 mt-0.5 flex-shrink-0" />
        <div className="flex-1 min-w-0">
          <p className="text-sm font-medium text-red-900 dark:text-red-100">Invalid file</p>
          <p className="text-sm text-red-700 dark:text-red-300 mt-0.5">{currentError}</p>
        </div>
        <button
          type="button"
          onClick={() => setIsVisible(false)}
          className="flex-shrink-0 w-5 h-5 flex items-center justify-center rounded hover:bg-red-100 dark:hover:bg-red-900/50 text-red-600 dark:text-red-400 transition-colors"
          aria-label="Dismiss"
        >
          <X className="size-4" />
        </button>
      </div>
    </div>
  )
}
